allow:
Bash(powershell.exe -NoProfile -Command "
# Move contents from app/invoice/* to app/ \(overwrite existing\)
$src = ''E:\\THOLIB\\wordpress\\invoice.rizquna.id\\app\\invoice''
$dst = ''E:\\THOLIB\\wordpress\\invoice.rizquna.id\\app''

# Move directories
$dirs = @\(''app'',''bootstrap'',''config'',''database'',''resources'',''routes'',''storage'',''tests'',''vendor'',''.git'',''.vscode''\)
foreach \($d in $dirs\) {
    if \(Test-Path \(Join-Path $src $d\)\) {
        $target = Join-Path $dst $d
        if \(Test-Path $target\) { Remove-Item $target -Recurse -Force }
        Write-Host \(''Moving '' + $d + ''...''\)
        Move-Item -Path \(Join-Path $src $d\) -Destination $target -Force
    }
}

# Move files \(only ones that should overwrite or are new\)
$files = @\(''webpack.mix.js'',''.DS_Store''\)
foreach \($f in $files\) {
    if \(Test-Path \(Join-Path $src $f\)\) {
        Write-Host \(''Moving '' + $f + ''...''\)
        Move-Item -Path \(Join-Path $src $f\) -Destination \(Join-Path $dst $f\) -Force
    }
}

# Remove the leftover invoice directory
Remove-Item $src -Recurse -Force
Write-Host ''Done!''
")
